243	static ngx_inline void
244	ngx_http_v2_queue_frame(ngx_http_v2_connection_t *h2c,
245	    ngx_http_v2_out_frame_t *frame)
246	{
247	    ngx_http_v2_out_frame_t  **out;
248	
249	    for (out = &h2c->last_out; *out; out = &(*out)->next) {
250	
251	        if ((*out)->blocked || (*out)->stream == NULL) {
252	            break;
253	        }
254	
255	        if ((*out)->stream->node->rank < frame->stream->node->rank
256	            || ((*out)->stream->node->rank == frame->stream->node->rank
257	                && (*out)->stream->node->rel_weight
258	                   >= frame->stream->node->rel_weight))
259	        {
260	            break;
261	        }
262	    }
263	
264	    frame->next = *out;
265	    *out = frame;
266	}
